def checkShelfSafetyRed(groupids,mode) {
    my conflicts = List();
    my conflict_groupids = List();
    my check = true; /* zuwenig hoch oder L-Konfig oder Safety schon erfogreich bestaden und keine Artikelaenderung mehr */
    /* my articles = List();
    my group_articles = List();
    */
    my group_parts = List();
    my groupvolumes = List();
    my dim = List();
    my height = 0;
    my depth = 0;
    my width = 0;
    my hash = '';
    my hash_legacy = '';
    my hash_today = '';
    my safety_hash = '';
    my hash_ok = false;

    my store = null;
    my safety_assigned = false;
    my dimensionfactor = safetyparams['name','statics']['static']['name','dimensionfactor']['value'];
    for (my groupid : groupids) {
      check = true;
      group_parts = call groupIdPartList(groupid);
      store =  call safetyDummy(group_parts);
      dim = call groupIdDimemsions(group_parts,'both');
      height = dim[0];
      width = dim[1]; /* kurze Seite */
      depth = dim[2]; /* lange Seite */


      /********** CHECK safety_confirmation **************/
      if (store) {
        if (Feature(store,'safety_confirmation')) {
          check = false;
        }
      }
      /********** CHECK Form constrains **************/
      if (check) {
        check = not call winkelRegal(group_parts);
      }
      /********** CHECK Korpus **************/
      if (check) {
        my schubladen = Bool(Size(FilterList(group_parts,'element',`not IsSubTypeOf(element,'schublade');`)));
        if (schubladen) {
          my dim1 = width eq 395 and depth eq 500 and height lt 745;
     	 /* wdith wird zu depth, da breiter als tiefe */
     	  my dim2 = width eq 500 and depth eq 750 and height le 789;
          if (dim1 or dim2) {
            check = false;
          }
        }
      }

      /********** CHECK Part Changes **************/     
      if (check) {
        hash = call hashParts(group_parts,'innerparts'); /* without innerparts */
        hash_today = call hashParts(group_parts,'today'); /* without Fuesse und Rollen */
        hash_legacy = call hashParts(group_parts,'legacy'); /* all parts */
        my complete = call safetyParamStore(store,'complete') eq 1;
        safety_assigned = call safetyParamStore(store,'safetyAssigned') eq 1;
        safety_hash = call safetyParamStore(store,'hashParts');
        hash_ok = safety_hash eq hash or safety_hash eq hash_legacy or safety_hash eq hash_today;
        if (safety_assigned and hash_ok) {
          if ( call safetyParamStore(store,'safetyLevel') le 1) {
            check = false;
          }
        } else if (safety_assigned and not hash_ok) {
           check = true;
          if (mode eq 'save' and complete) {
            /* wenn complete, dann ist ein safety-tool angewandt worden */
            /* dann kann das save-safety-check das nicht selbst bewerten */
            /* sondern safety-check muss interaktiv gemacht werden */
            check = false;
          }
       }
      } 

      /********** CHECK COMPLETE NON CALCULATED PARTS **************/     
      if (check) {
        group_parts = FilterList(group_parts,'element',`IsSubTypeOf(element, 'co_safety_dummy');`);
        my values = FeatureValuesFromPartList(group_parts, 'calculated');
        values = UniqueList(values);
        if (not InList(values,'true')) {
            check = false;
        }
        check;
      } 

       /********** CHECK co_safety_dummy noch nicht vorhanden **************/

      /* neu erstellt im interaktiven modus: Roter Konflikt, aber nur als Hinweis */

      if (mode ne 'save') {
        if (not safety_assigned and mode ne 'hint' or (mode eq 'hint' and safety_assigned and not hash_ok)) {
          check = false;
        }
      }


      if (check) {
        groupvolumes = call groupIdVolumeList(groupid);
        groupvolumes = ListReverse(groupvolumes);
        conflicts = JoinList(conflicts, groupvolumes);
        conflict_groupids = ListAdd(conflict_groupids,groupid);
      }
    }
    if (mode eq 'save') {
      conflicts = conflict_groupids;
    }
    /* WriteInfoLog('SAFETY: ' ++ DumpToString(groupids)); */
    return conflicts;
   }

def checkShelfSafetyOrange(groupids) {
    my conflicts = List();
    my check = false; /* Korpus oder L-Konfig oder Safety schon erfogreich bestanden und keine Artikelaenderung mehr */
    my values = List();
    my group_articles = List();
    my group_parts = List();
    my store = null;
    my groupvolumes = List();
    my hash = '';
    my hash_legacy = '';
    my hash_safety = '';
    my hash_today = '';
    my safety_hash = '';
    my hash_ok = false;

    for (my groupid : groupids) {
      check = false;
      group_parts = call groupIdPartList(groupid);
      store =  call safetyDummy(group_parts);
      hash = call hashParts(group_parts,'innerparts'); /* without innerparts */
      hash_today = call hashParts(group_parts,'today'); /* without Fuesse und Rollen */
      hash_legacy = call hashParts(group_parts,'legacy'); /* all parts */
      safety_hash = call safetyParamStore(store,'hashParts');
      hash_ok = safety_hash eq hash or safety_hash eq hash_legacy or safety_hash eq hash_today;
      if ( call safetyParamStore(store,'safetyLevel') eq 1 and hash_ok) {
        check = true;
      }
      if (check) {
        /* Besteht das ganze Moebel auch nicht-kalkulierte Teilen, fassl ja muss es nicht geprueft werden */
        group_parts = FilterList(group_parts,'element',`IsSubTypeOf(element, 'co_safety_dummy');`);
        my values = FeatureValuesFromPartList(group_parts, 'calculated');
        values = UniqueList(values);
        if (not InList(values,'true')) {
            check = false;
        }
      }
      if (check) {
        groupvolumes = call groupIdVolumeList(groupid);
        groupvolumes = ListReverse(groupvolumes);
        conflicts = JoinList(conflicts, groupvolumes);
      }
    }
    /* WriteInfoLog('SAFETY: ' ++ DumpToString(groupids)); */
    return conflicts;
   }

def allSafetyParams(groupid,articles,mode) {
    my params = List(); 
    my kippgefahr = List();
    my kippgefahr_extern = List();
    my dimensions = List();
    my group_parts = call groupIdPartList(groupid);
    my noncalulatedparts = false;
    my group_articles = FilterList(articles,'element',`element['groupid'] ne groupid;`);
    my hasAZE = Bool(FilterList(group_parts,'element',`not IsSubTypeOf(element,'teleskopauszug');`)[0]);
    my hasSLA = Bool(FilterList(group_parts,'element',`not IsSubTypeOf(element, 'schubladenauszug');`)[0]);
    my hasDOOR = Bool(FilterList(group_parts,'element',`not IsSubTypeOf(element, 'tuerelement');`)[0]); 
    my kugeln = FilterList(group_parts,'element',`not IsSubTypeOf(element,'kugel_std');`);
    my boden_kugeln = Size(FilterList(kugeln,'element',`PartPos(element)['z'] gt 14;`));
    my hasCharge = hasAZE or hasSLA;
    my hasMovable = hasAZE or hasSLA or hasDOOR;


    my ggw_count_userinput = 99999; /* gewuenschte Anzahl GGPL */
    my ggw_weight_userinput = 0; /* Gewicht basierend auf gewuenschte Anzahl GGPL */
    my kippgefahrExtern = List();
    my haskippgefahrExtern = false;
    my haskippgefahrMovable = false;
    my calcAZE = false;
    my griffe = call shelfGriffList(group_parts);
    my hasGriffe = Bool(griffe[0]);
    my hasRollen = call shelfHasRollen(group_articles);
    my count_ggw_articles = Size(FilterList(group_articles,'element',`not InRange(18600,18604,element['key']);`));
    my safetyAssigned = 0;

    my diffweightExtern = List();
    my diffweightMovable = List();
    my charge = List();
    my charge_azt = safetyparams['name','forces']['force']['name','charge_azt']['value'];    
    my charge_schublade = safetyparams['name','forces']['force']['name','charge_schublade']['value'];
    my charge_azt_gui = charge_azt;

    /* Werte aus dem gespeicherten Mobel */
    /* if (mode eq 'create' and existSafetyAssigned) {

    } */
    /* Werte aus Benutzer-Eingabe braucht Neuberechnung*/
    if (mode eq 'update') {
      if (Bool(NamedNode('safety_gui'))) {
        my node = NamedNode('safety_gui');
        if (NodeValue(node,'ggw_insertion_userinput')) {
          my blecheGGW = call groupBlechListGGW(group_parts);
          ggw_count_userinput = NodeValue(node,'ggw_count_userinput');
          my assigned_ggws = call assignGGW(blecheGGW,99999,ggw_count_userinput);
          ggw_weight_userinput = assigned_ggws[2];
        } else if (NodeValue(node,'ggw_insertion')) {
          my blecheGGW = call groupBlechListGGW(group_parts);
          ggw_count_userinput = NodeValue(node,'ggw_count');
          my assigned_ggws = call assignGGW(blecheGGW,99999,ggw_count_userinput);
          ggw_weight_userinput = assigned_ggws[2];

        }
      }
    }

    /* Zuerst wird das externe GegenGewicht berechnet */
    dimensions = call groupIdDimemsions(group_parts,'extern');      
    diffweightExtern = call diffGewichtExtern(group_parts,group_articles,hasRollen,dimensions,ggw_weight_userinput,mode);
    kippgefahr = call kippGefahrRegal('extern',diffweightExtern);
    kippgefahr_extern = kippgefahr;
    haskippgefahrExtern = kippgefahr[0] gt 0;  
    if (hasMovable) {    
       /* Nun wird das Ueberladungs-Gewicht berechnet */
       dimensions = call groupIdDimemsions(group_parts,'aze');
       diffweightMovable = call diffGewichtMovable(group_parts,group_articles,dimensions,ggw_weight_userinput,hasAZE,hasSLA,hasDOOR,mode);
       /* Message('gp ; ' ++ group_parts ++ ' ga ; ' ++ group_articles ++ ' mw ; ' ++ minwidth ++ ' ggwuser ; ' ++ ggw_weight_userinput ++ ' hasAZE ; ' ++ hasAZE ++ ' hasSLA ; ' ++ hasSLA ++ ' hasDOOR ; ' ++ hasDOOR); */
       kippgefahr = call kippGefahrRegal('aze',diffweightMovable);
       haskippgefahrMovable = kippgefahr[0] gt 0;
       charge_azt_gui = diffweightMovable[6];
      if (-diffweightExtern[0] lt -diffweightMovable[0]) {
        /* Wenn mehr AZE Gegengewicht notwendig, dann ist AZE fuehrend */
        calcAZE = true;
      } else {
         kippgefahr = kippgefahr_extern;
      }
    }
    params[0] = safetyAssigned; /* safety already assigned, BOOL */
    params[1] = haskippgefahrMovable; /* tilt danger cause of pull-out elements , BOOL */
    params[2] = kippgefahr; /* safetylevel 0,1,2 and names of level */
    params[3] = count_ggw_articles;
    params[4] = boden_kugeln; /* how many sphere at the bottom of a shelf */ 
    params[5] = kippgefahr[0]; /* safetylevel 0,1,2*/
    params[6] = group_parts; /* list of parts inside a group (shelf complete) */
    params[7] = mode; /* create, update */
    params[8] = ggw_count_userinput; /* gewuenschte Anzahl GGPL */
    params[9] = diffweightExtern[2]; /* Gesamtgewicht */
    params[10] = hasRollen; /* has rolls, BOOL */
    params[11] = group_articles; /* list of articles inside a group (shelf complete) */
    params[12] = haskippgefahrExtern; /* tilt danger cause of human force , BOOL */
    params[13] = hasCharge; /* has weight on pull-out shelfs , BOOL */
    params[14] = dimensions; /* [0]: Hoehe + [1] : minTiefe + Breite [2] in mm*/
    params[15] = diffweightExtern; /* Gewichtsberechnungen Anlehnen */
    params[16] = charge_schublade; /* weight on pull-out drawer , kg */
    params[17] = charge_azt; /* weight on pull-out shelfs , kg */
    params[18] = calcAZE;  /* calculation cause pull-out elements, BOOL */
    params[19] = charge_azt_gui; /* weight on pull-out elements, changeable by user in GUI, kg */
    params[20] = diffweightMovable[7]; /* Anzahl AZTs, count pull-out shelfs */
    params[21] = diffweightMovable[8]; /* Anzahl Schubladen, count pull-out drawer */
    params[22] = diffweightMovable; /* Gewichtsberechnungen AZT */
    params[23] = ggw_weight_userinput; /* Gewicht GGPL, weight of contre-weight elements*/
    params[24] = hasSLA and not hasAZE; /* hat nur Schubladen und keine AZTs, has only drawers*/
    params[25] = griffe; /* vorhandene Griffe,  list of handles*/
    params[26] = hasGriffe; /* sind  Griffe vorhanden, are handles used ? */
    /* call allSafetyParams(0,_articles,'create'); */
    return params;
  }

def diffGewichtMovable(group_parts,group_articles,dimensions,ggw_weight_userinput,hasAZE,hasSLA,hasDOOR,mode) {
    /* WriteInfoLog(minwidth ++ ', ' ++ ggw_weight_userinput ++ ', ' ++ hasAZE ++ ', ' ++ hasSLA ++ ', ' ++ hasDOOR ++ ', ' ++ mode); */
    my diffs = List();
    my diff_gewicht = 0;
    my diff_moment = 0;
    my charge = 0;
    my minwidth = dimensions[1];
    my telelength = dimensions[3];
    my weight_static = 0;

    my charge_azt = safetyparams['name','forces']['force']['name','charge_azt']['value'];  
    charge_azt = (telelength eq 500 or telelength eq 750) ? safetyparams['name','forces']['force']['name','charge_azt500-750']['value']:charge_azt;  
    my charge_schublade = safetyparams['name','forces']['force']['name','charge_schublade']['value'];
    my sec_weightfactor = safetyparams['name','statics']['static']['name','securityweightfactor']['value'];
    my selfmomentfactor = safetyparams['name','statics']['static']['name','selfmomentfactor']['value'];

    my belastung = call groupIdCharge(group_parts,charge_azt,charge_schublade);    
    my shelf_weight_full = call groupIdWeight(group_articles,'full');
    my weight_full = shelf_weight_full[0];
    my weight_movable = 0;
    my weight_door = 0;
    my weight_doors = 0;
    my weight_aze = 0;
    my weight_sla = 0;
    my count_azt = 0;
    my count_doors = 0;


    if (hasDOOR) {
       my count_max_doors = Size(FilterList(group_parts,'element',`not IsSubTypeOf(element, 'tuerelement');`));
       my azt_doors = Size(FilterList(group_parts,'element',`not IsSubTypeOf(element, 'tablarwinkel');`)) / 2;
       my weight_doors = call groupIdWeight(group_articles,'door');
       weight_doors = weight_doors[0];
       if (count_max_doors gt 0) {
         weight_door = weight_doors / count_max_doors;
       } else if (azt_doors gt 0) {
         weight_door = weight_doors / azt_doors;
       }
       count_doors = count_max_doors - azt_doors;
       weight_doors = weight_door * count_doors;
       weight_movable = 0; /* Klapptuere wird nicht berechnet */

    }    
    if (hasAZE) {
       count_azt = belastung[3];

    /* max_azt wird gebraucht um auf ein AZT runterzubrechen bei den Artikelgewichten */
       my max_azt = count_azt + belastung[5]; /* plus static AZTs */

       my weight_aze = call groupIdWeight(group_articles,'aze');
       weight_aze = weight_aze[0];

       weight_aze = weight_aze / max_azt * count_azt;

       weight_aze = weight_aze + (weight_door * count_azt);

       /* Message('m ; ' ++ weight_movable ++ ' aze ; ' ++ weight_aze ++ ' doors ; ' ++ weight_doors * count_azt ++ ' charge ; ' ++ belastung[0]); */
       weight_movable = weight_movable + weight_aze + belastung[0];

    }
    if (hasSLA) {
       my count_sla = belastung[4];
    /* max_sla wird gebraucht um auf einn AZT runterzubrechen bei den Artikelgewichten */
       my max_sla = count_sla + belastung[6];
       weight_sla = call groupIdWeight(group_articles,'sla');
       weight_sla = weight_sla[0];
       weight_sla = weight_sla / max_sla * count_sla;
       weight_movable = weight_movable + weight_sla + belastung[1];
    }

    /* Message(weight_full ++ ', ' ++ weight_doors ++ ', ' ++ weight_aze ++ ', ' ++ weight_sla); */
    weight_static = weight_full - weight_aze - weight_sla;
    weight_static = weight_static / sec_weightfactor;
    my charge_azt_gui = charge_azt;
    selfmomentfactor = selfmomentfactor * minwidth;  

    /****** choosen security feature will be applied ******/
    my addition_moment = 0;
    my addition_weight = 0;
    my node = null;   
    if (mode eq 'update') {
      if (Bool(NamedNode('safety_gui'))) {
        node = NamedNode('safety_gui');
        if (NodeValue(node,'wall_anchoring') or NodeValue(node,'floor_anchoring') or NodeValue(node,'shelf_connector')) {
         /* addition_moment = NodeValue(node,'missing_moment') * -1 ; 
          addition_weight = NodeValue(node,'missing_weight'); 
         */
          addition_moment = - NodeValue(node,'missing_moment') + 10000; 
          addition_weight = (- NodeValue(node,'missing_moment') + 10000) / selfmomentfactor;
        }
        if (NodeValue(node,'ggw_insertion')) {
          addition_moment = ggw_weight_userinput * selfmomentfactor; 
          addition_weight = ggw_weight_userinput; 
        }
        if (NodeValue(node,'ggw_insertion_userinput')) {
          addition_moment = ggw_weight_userinput * selfmomentfactor; 
          addition_weight = ggw_weight_userinput; 

        }
      }
    }

    /****** security will be  calculated ******/
    diff_gewicht = weight_static - weight_movable + addition_weight;
    /* Hier wurde gemaess Excel das Gesamtgewicht genommen */
    my own_moment = weight_static * selfmomentfactor + addition_moment;
    my moveable_moment = weight_movable * selfmomentfactor;
    my diff_moment = own_moment - moveable_moment;
    /* Message(diff_moment); */
    /* Wieviel Gewicht darf noch auf den Tablaren sein, damit Moment positiv wird */
    if (hasAZE and InRange(-10001,1,diff_moment)) {
      my weight_movable_gui = weight_static - weight_movable + ggw_weight_userinput;
      /* Message(weight_static ++ ' - ' ++ weight_movable); */
      my charge_azt_gui = weight_movable_gui /count_azt;
      charge_azt_gui = charge_azt_gui + charge_azt;  
      if (charge_azt_gui gt charge_azt) {
        /* wenn Tablar mehr tragen koennte als dessen max. Belastung */
        charge_azt_gui = charge_azt;
      } else if (charge_azt_gui lt 0) {
         /* wenn Tablar weniger als nichts tragen kann */
         charge_azt_gui = 0;
      }
    }  

    diffs[0] = diff_gewicht;
    diffs[1] = diff_moment;
    diffs[2] = belastung[0]; /* AZT */
    diffs[3] = belastung[1]; /* Schubladen */
    diffs[4] = weight_static;
    diffs[5] = weight_movable;
    diffs[6] = charge_azt_gui; /* reduzierte Belastung */
    diffs[7] = belastung[3]; /* count AZT */
    diffs[8] = belastung[4]; /* count schubladen */
    diffs[9] = shelf_weight_full[1]; /* moveable articles */
    diffs[10] = count_doors; /* Normale Tueren */
    /* call diffGewichtMovable(group_parts,group_articles,minwidth,ggw_weight_userinput,hasAZE,hasSLA,hasDOOR,mode); */
    /* call diffGewichtMovable(_sftparams[6],_sftparams[11],350,3,1,0,0,'create'); */
    return diffs;
    }

def diffGewichtExtern(group_parts,group_articles,rollen,dimensions,ggw_weight_userinput,mode) {
    my diffs = List();
    my diff_gewicht = 0;
    my ext_force = safetyparams['name','forces']['force']['name','anlehnen']['value'];
    if (rollen) {
       ext_force = safetyparams['name','forces']['force']['name','anlehnen_rollen']['value'];
    }
    my dimensionfactor = safetyparams['name','statics']['static']['name','dimensionfactor']['value'];
    my selfmomentfactor = safetyparams['name','statics']['static']['name','selfmomentfactor']['value'];
    my securityweightfactor = safetyparams['name','statics']['static']['name','securityweightfactor']['value'];
    my own_moment = 0;
    my ext_moment = 0;
    my diff_moment = 0;
    my height = dimensions[0];
    if (height le 1000) {
    	ext_force = height/100;
    	if (rollen) {
    		ext_force = ext_force * 1.5;
    	};	
    };
    my depth = dimensions[1];
    selfmomentfactor = selfmomentfactor * depth;
    if (securityweightfactor gt 0) {
      selfmomentfactor = selfmomentfactor/securityweightfactor;
    }
    my weight = call groupIdWeight(group_articles,'full');
    weight = weight[0];
    /****** choosen security feature will be applied ******/
    my addition_moment = 0;
    my addition_weight = 0;
    my node = null;
    if (mode eq 'update') {
      if (Bool(NamedNode('safety_gui'))) {
        node = NamedNode('safety_gui');
        if (NodeValue(node,'wall_anchoring') or NodeValue(node,'floor_anchoring') or NodeValue(node,'shelf_connector')) {
          addition_moment = - NodeValue(node,'missing_moment') + 10000;
          addition_weight = NodeValue(node,'missing_weight'); 
        }
        if (NodeValue(node,'ggw_insertion')) {
          addition_moment = ggw_weight_userinput * selfmomentfactor; 
          addition_weight = ggw_weight_userinput; 
        }
        if (NodeValue(node,'ggw_insertion_userinput')) {
          addition_moment = ggw_weight_userinput * selfmomentfactor; 
          addition_weight = ggw_weight_userinput; 
        }
      }
    }
    /********** Calculate Diff Weight **************/
    own_moment = Round(weight * selfmomentfactor) + addition_moment;
    ext_moment = ext_force * height;
    diff_moment = own_moment - ext_moment;
    if (selfmomentfactor ne 0) {
      /* notwendiges Gewicht um das Eigenmoment gleich gross zu machen, wie das externe Moment */
      diff_gewicht = diff_moment / selfmomentfactor;
    }
    diffs[0] = diff_gewicht;
    diffs[1] = diff_moment;
    diffs[2] = weight; /* Gesamt Gewicht */
    return diffs;
 }

def groupIdCharge(group_parts,charge_azt,charge_schublade) {
    my charge = 0; /* kg */
    my azts = call countAZT(group_parts);
    my movable_azts = azts[0];
    my static_azts = azts[1];
    my schubs = call countSchubladen(group_parts);
    my movable_schubs = schubs[0];
    my static_schubs = schubs[1];
    my schub_charge = movable_schubs * charge_schublade;
    my azt_charge =  movable_azts * charge_azt;
    charge[0] = azt_charge;
    charge[1] = schub_charge;
    charge[2] = azt_charge + schub_charge;
    charge[3] = movable_azts;
    charge[4] = movable_schubs;
    charge[5] = static_azts;
    charge[6] = static_schubs;
    return charge;
   }

def kippGefahrRegal(type,charge) {
    my kippgefahr = List();
    my level_0 = safetyparams['name','kippgefahr']['level']['code','level_0'];
    my level_1 = safetyparams['name','kippgefahr']['level']['code','level_1'];
    my level_2 = safetyparams['name','kippgefahr']['level']['code','level_2'];

    /********** Calculate Extern **************/
    my diffweight = charge[0];
    my diffmoment = charge[1];
    kippgefahr[1] = diffweight;
    kippgefahr[3] = diffmoment;
    my weight = charge[2];
    if (diffmoment ge level_0['lower']) {
    	kippgefahr[0] = 0;
       kippgefahr[2] = level_0['name'];
    } else if (diffmoment lt level_0['lower'] and diffmoment ge level_1['lower']) {  
       kippgefahr[0] = 1;
       kippgefahr[2] = level_1['name']; 
    } else if (diffmoment lt level_1['lower']) {
          kippgefahr[0] = 2;
          kippgefahr[2] = level_2['name'];
    }
        /*
        /*
        o Unbedenklich = nur wenn WV, BV oder RV + alle positiven Werte Restkippmoment
        o Bedingt benutzbar = Werte von 0 bis -10000 
        o kippgefährdet = Werte von -10000 bis -999999 
        */
      kippgefahr[1] = -1 * kippgefahr[1]; /* positiv setzen fuer GGPL Berechnung */
    return kippgefahr;
 }

def shelfHasRollen(group_articles) {
    my hasRollen = false; 
    my rollen_std = FilterList(group_articles,'element',`not InRange(10761,10762,element['key']);`);
    my rollen_brems = FilterList(group_articles,'element',`not InRange(12066,12067,element['key']);`);
    my rollen_gross = FilterList(group_articles,'element',`not InRange(18880,18881,element['key']);`);
    my rollen = JoinList(JoinList(rollen_std,rollen_brems),rollen_gross);
    hasRollen = Bool(Size(rollen));
    return hasRollen;
  }

def shelfGriffList(group_parts) {
    my griffList = List();
    my griffe = FilterList(group_parts,'element',`not IsSubTypeOf(element,'schlossgriff');`);
    griffList[0] = Bool(Size(griffe));
    griffList[1] = FilterList(griffe,'element',`not IsSubTypeOf(element,'griff_normal');`);
    griffList[2] = FilterList(griffe,'element',`not IsSubTypeOf(element,'schnapp_griff_normal');`);
    griffList[3] = FilterList(griffe,'element',`not IsSubTypeOf(element,'griff_m_nummer');`);
    griffList[4] = FilterList(griffe,'element',`not IsSubTypeOf(element,'schnapp_griff_m_nummer');`);
    return griffList;
  }

def showPlattenGGW(part,pos) {

  	if (not IsSubTypeOf(part, 'co_gewichtplatte')) {
  		return false;
  	} else {
  		part = FindPart(part, 'ggw_2_blech',1);
  	};

    my show = false;
    my max = List();
    my positions = 0;
    my frontseitenormal = true;
    if (part) {
      positions = Feature(part,'f_ggwPositionen');
      /* frontseitenormal = call frontSeiteNormal(part);
      /* if (call plattenRichtungNormalGGW(part) or frontseitenormal[1]) { */
      if (not call yDirectionGGW(part)) {
        if (positions ge pos) {
          show = true;
        }
      } else {
        max = call maxPlattenGGW(part);
        /* Message(max[0] ++ ', ' ++ pos ++ ', ' ++ positions); */
        if ((pos le max[0]) and (pos gt (max[0] - positions))) {
         show = true;
        }
      }
    }
    return show;   
  }

