def groupIdDimemsions(parts,mode) {
    my dimensions = List();
    my dim = List();
    my unit = 'mm';
    my imperialfactor = 25.4;
    my maxheight = 1;
    my minwidth = 1;
    my maxwidth = 1;
    my kugeln = FilterList(parts,'element',`not IsSubTypeOf(element,'kugel_std');`);
    my teleskope = FilterList(parts,'element',`not IsSubTypeOf(element,'teleskopauszug');`);
    my teleskop = teleskope[0];
    my teleskop_length = 1;
    my zlist = List();
    for (my i : IndexList(Size(kugeln))) {
      zlist[i] = PartPos(kugeln[i])['z'];
    }
    maxheight = ListMax(zlist);
    maxheight = Round( (maxheight * 10) + 10 ) ;
    /* lowest Kugelreihe is filtered out */
    kugeln = FilterList(kugeln,'element',`PartPos(element)['z'] gt 14;`); 
    if (Size(kugeln) gt 2) {
      /* min. 3 kugeln are needed */
      dim = call findDepth(kugeln);
      minwidth = dim[0];
      maxwidth = dim[1];
    }
    if (mode eq 'aze' and Bool(teleskop)) {
      teleskop_length = PartAttr(teleskop,'length');
      if (teleskop_length gt minwidth) {
        minwidth = teleskop_length;
      }
    }
    dimensions[0] = Round(maxheight);
    dimensions[1] = Round(minwidth);
    dimensions[2] = Round(maxwidth);
    dimensions[3] = Round(teleskop_length); /* Teleskop Laenge */

    if (mode eq 'measure') {
			if (UnitSystem() eq 'imperial') {
				unit = '"';
				for (my i : IndexList(Size(dimensions))) {
					dimensions[i] = Round(dimensions[i] / imperialfactor, 0.01);
				}
			}
		}
		dimensions[4] = unit;    
    return dimensions; /* in mm or inches*/
   }

def findDepth(kugeln) {

    my dim = List(1,1);
    if (Size(kugeln)) {
      my ref = kugeln[0];
      my min = Vector(0,0,0);
      my max = Vector(0,0,0);

      for (my kugel : kugeln) {
       my pos = RelativePartPos(ref, kugel);
       min['x'] = Min(min['x'], pos['x']);
       min['y'] = Min(min['y'], pos['y']);
       min['z'] = Min(min['z'], pos['z']);
       max['x'] = Max(max['x'], pos['x']);
       max['y'] = Max(max['y'], pos['y']);
       max['z'] = Max(max['z'], pos['z']);
      }
      my delta = VectorSub(max, min);
      my dims = SortByValue(List(Round(delta['x'],0.01),Round(delta['y'],0.01),Round(delta['z'],0.01)),'Round(element,0.01);');
      my depth = Round(dims[1] * 10);
      my width = Round(dims[2] * 10);
      dim[0] = depth;
      dim[1] = width;
    }
    return dim;
    }

def lowerLeftKugel(parts) {
    my lowerLeftKugel = null;
    if (not IsObject(parts[0])) {
      parts = call groupIdPartList(parts);
    }
    my kugeln = FilterList(parts,'element',`not IsSubTypeOf(element,'kugel_std');`);
    kugeln = FilterList(kugeln,'element',`PartPos(element)['z'] gt 14;`);
    my dist = 0;
    my mindist = 99999;
    my pos = Vector();
    for (my kugel : kugeln) {
      pos = PartPos(kugel);
      dist = pos['x'] + pos['y'];
      if (dist lt mindist) {
        mindist = dist;
        lowerLeftKugel = kugel;
      }
    }
    return lowerLeftKugel;
  }

def lowerLeftBodenelement(parts) {
    my lowerLeftBodenelement = null;
    if (not IsObject(parts[0])) {
      parts = call groupIdPartList(parts);
    }
    my bodenelement = FilterList(parts,'element',`not IsSubTypeOf(element,'bodenelement');`);
    bodenelement = Size(bodenelement) eq 0 ? FilterList(parts,'element',`not IsSubTypeOf(element,'tischbein');`) : bodenelement;
    bodenelement = FilterList(bodenelement,'element',`PartPos(element)['z'] gt 14;`);
    my dist = 0;
    my mindist = 99999;
    my pos = Vector();
    for (my b : bodenelement) {
      pos = PartPos(b);
      dist = pos['x'] + pos['y'];
      if (dist lt mindist) {
        mindist = dist;
        lowerLeftBodenelement = b;
      }
    }
    return lowerLeftBodenelement;
  }

