def hashParts(group_parts,mode) {
    my hash = '';
    my partsstring = '';
    my parts = List();
    group_parts = FilterList(group_parts,'element',`IsSubTypeOf(element,'volcontconnector');`);
    group_parts = FilterList(group_parts,'element',`IsSubTypeOf(element,'co_safety_dummy');`);
    group_parts = FilterList(group_parts,'element',`IsSubTypeOf(element,'co_qs_article');`);
    group_parts = FilterList(group_parts,'element',`IsSubTypeOf(element,'co_gewichtplatte');`);
    group_parts = FilterList(group_parts,'element',`IsSubTypeOf(element,'ct_soft_panel');`);
    if (mode eq 'today') {
	    group_parts = FilterList(group_parts,'element',`IsSubTypeOf(element,'fuesse');`);
	    group_parts = FilterList(group_parts,'element',`IsSubTypeOf(element,'ct_griff');`);
    } else if (mode eq 'innerparts') {
      group_parts = FilterList(group_parts,'element',`IsSubTypeOf(element,'ausruestung');`);
      group_parts = FilterList(group_parts,'element',`IsSubTypeOf(element,'ct_kastenset');`);
      group_parts = FilterList(group_parts,'element',`IsSubTypeOf(element,'frontblende');`);
      group_parts = FilterList(group_parts,'element',`IsSubTypeOf(element,'ct_trennwaende');`);
      group_parts = FilterList(group_parts,'element',`IsSubTypeOf(element,'ct_inosBoxKonzept');`);
      group_parts = FilterList(group_parts,'element',`IsSubTypeOf(element,'einsatz');`);
      group_parts = FilterList(group_parts,'element',`IsSubTypeOf(element,'schubladen_profil');`);
      group_parts = FilterList(group_parts,'element',`IsSubTypeOf(element,'schubladenrahmen');`);
      group_parts = FilterList(group_parts,'element',`IsSubTypeOf(element,'karteikasten');`);
      group_parts = FilterList(group_parts,'element',`IsSubTypeOf(element,'schraegfach');`);
      group_parts = FilterList(group_parts,'element',`IsSubTypeOf(element,'schalenzubehoer');`);
      group_parts = FilterList(group_parts,'element',`IsSubTypeOf(element,'gleitprofil');`);
      group_parts = FilterList(group_parts,'element',`IsSubTypeOf(element,'rillenplatte');`);
      group_parts = FilterList(group_parts,'element',`IsSubTypeOf(element,'schieberelement');`);
      group_parts = FilterList(group_parts,'element',`IsSubTypeOf(element,'disthalter_register');`);
      group_parts = FilterList(group_parts,'element',`IsSubTypeOf(element,'ct_trennwaende');`);
      group_parts = FilterList(group_parts,'element',`IsSubTypeOf(element,'schubladen_profil');`);
    }
    my sortex = 'StrAlphabeticalCompare(GetTypeName(element1), GetTypeName(element2));';
    group_parts = Sort(group_parts, sortex);

    for (my i : IndexList(Size(group_parts))) {
      parts[i]['name'] = GetTypeName(group_parts[i]);
      parts[i]['quantity'] = 1;
    }

    parts = CompressTable(parts, List('name'), List('quantity'));
    for (my part : parts) {
      partsstring = partsstring ++ part['quantity'] ++ part['name'];
    }
    hash = HashMD5(partsstring);
    return hash;
    }

def groupIdWeight(group_articles,mode) {
    my weightInfo = List();
    my weight = 0;
    my weightSLA = 0;
    my weightAZE = 0;
    my weightDOOR = 0;
    my weightStatic = 0;
    my weightArticle = 0; 
    my weightFull = 0;

    my movetag = ''; /* 1 = general incl. Schubladen, 2 = AZT, 3 = Klap- und AZT-Tueren */
    my key = '';
    my basenr = '';
    my securitylist = List();
    my nonweightlist = List();
    my securityarticles = List();

    for (my securityarticle : safetyMovArticles) {
       securitylist = ListAdd(securitylist, securityarticle['key']);
    }
    for (my noneweightarticle : safetyNoneWeightArticles) {
       nonweightlist = ListAdd(nonweightlist, noneweightarticle['key']);
    }
    for (my article : group_articles) {
        key = article['key'];
        weightArticle = 0;
        if (not InList(nonweightlist,key)) {
            weightArticle = BASE['Anr',key]['Gewicht'];
            weightFull = weightFull + weightArticle;
        }
        if (InList(securitylist,key)) {
        /* safetyMovArticles = Liste aller ausziehbaren Artikel durch USM verwaltet */
          movetag = safetyMovArticles['key',key]['movable'];
          /* safetyMovArticles written to log) */
          my i = Size(securityarticles) + 1;
          securityarticles = ListAdd(securityarticles, movetag ++ ' ' ++ i ++ '  ' ++ key);
          if (movetag eq 1) {
            weightSLA = weightSLA + weightArticle;
          } else if (movetag eq 2) {
            weightAZE = weightAZE + weightArticle;
          } else if (movetag eq 3) {
            weightDOOR = weightDOOR + weightArticle; 
          }
        } else {
            weightStatic = weightStatic + weightArticle;
        }
      }

      if (mode eq 'sla') {
         weight = weightSLA;       
      } else if (mode eq 'aze') {
        weight = weightAZE;
      } else if (mode eq 'door') {
         weight = weightDOOR;
      } else if (mode eq 'static') {
        weight = weightStatic;
      } else if (mode eq 'full'){
        weight = weightFull;
      }
      /* WriteInfoLog('movables: ' ++ DumpToString(securityarticles)); */
      weightInfo[0] = weight;
      weightInfo[1] = securityarticles;
    return weightInfo;
  }

def maxWeightGGW(xlength,max,hallerE,kurzblech) {
    my maxweight = 0;
    my weight = 0;
    my length = 0;
    my aplweight = 0.02; /* Anschlussplatten */
    my headings = List('length','weight');
    my values = List('750',7.7,'500',4.8,'395E',3.5,'350',3.0,'395',5.7);
    my ggpls = CreateTable(headings, values);
    if (xlength eq 395) {
       if (hallerE) {
         length = '395E';
       } else if (kurzblech) {
         length = '350';
       } else {
        length = xlength;
       }
    } else {
      length = NumberToString(xlength,0);
    }
    weight = ggpls['length',length]['weight'];
    weight = weight + 2 * aplweight;
    maxweight = max * weight;
    return maxweight;
  }

def maxPlattenGGW(part) {
    my max = List();
    my ggplwidth = 10 + 1;
    my count = 2; /* Anzahl der Gewichtsplatten ausser der 750er, max. 2 Stk */
    my rawcount = count; /* Berechnente Anzahl der Gewichtsplatten */
    my ylength = 0;
    my xlength = 0;
    my vol = null;
    my hallerE = Feature(part,'f_hallerE');
    my kurzblech = BeginsWith(GetTypeName(part),'kurzblech');
    if (part) {
      ylength = PartAttr(part,'width')/10;
      xlength = PartAttr(part,'length')/10;
      if (call yDirectionGGW(part)) {
        ylength = PartAttr(part,'length')/10;
        xlength = PartAttr(part,'width')/10;
      }
    }
    rawcount = Floor(ylength/ggplwidth);
    if (rawcount gt 4) {
      count = 3;
    }
    max[0] = count; /* max. zugelassene Gewichtsplatten */
    max[1] = call maxWeightGGW(xlength,max[0],hallerE,kurzblech); /* MaximalGewicht der Gewichtsplatten fuer dieses Blech */
    max[2] = xlength * 10; /* Laenge der Gewichtsplatten */
    max[3] = rawcount; /* max. physisch moegliche Platten fuer geometrische Positionierung */
    return max;
  }

def lowerTwoRowsHeight(parts) {
    my heightlist = List();
    my kugeln = FilterList(parts,'element',`not IsSubTypeOf(element,'kugel_std');`);
    my zList = List();
    my pos = Vector();
    for (my i : IndexList(Size(kugeln))) {
      pos = PartPos(kugeln[i]);
      zList = ListAdd(zList, Round(pos['z']));
    }
    zList = UniqueList(zList);
    zList = SortByValue(zList, `element;`);
    /* die zwei Hoehen der untersten 2 Reihen */
    heightlist = List(zList[0],zList[1]);
    return heightlist;
  }

def groupBlechListGGW(parts) {
	  my ggwbleche = List();
	  my bleche = List();
	  my rowheights = call lowerTwoRowsHeight(parts);
	  my lowest  = rowheights[0];
	  my second = rowheights[1];
	  my lowestrow = List();
	  my secondrow = List();
	  bleche = FilterList(parts,'element',`not IsSubTypeOf(element,'metallverkleidung');`);
	  bleche = FilterList(bleche,'element',`call vertikalBlech(element);`);
	  my bleche2ggw = List('blech750_395_ggw','blech350_750_ggw','blech500_395_ggw','blech500_750_ggw','blech350_350_ggw','blech350_395_ggw','blech350_500_ggw','blech500_500_ggw');
    my kurzbleche2ggw = List('kurzblech750_395_ggw','kurzblech350_750_ggw','kurzblech500_395_ggw','kurzblech500_750_ggw','kurzblech350_395_ggw','kurzblech350_500_ggw','kurzblech500_500_ggw');
    my sperrbleche2ggw = List('sperrblech350_750_ggw','sperrblech500_750_ggw','sperrblech500_500_ggw','sperrblech350_500_ggw','sperrblech750_395_ggw','sperrblech500_395_ggw','sperrblech350_395_ggw');     

    bleche2ggw = JoinList(bleche2ggw,kurzbleche2ggw);
    bleche2ggw = JoinList(bleche2ggw,sperrbleche2ggw);

    for (my blech : bleche) {
      my posz = Round(PartPos(blech)['z']);
      if (InList(bleche2ggw,GetTypeName(blech) ++ '_ggw')) {
     	  if (InRange(lowest - 1,lowest + 1, posz)) {
     	 	 lowestrow = ListAdd(lowestrow,blech);
     	  } else if (InRange(second - 1,second + 1, posz)) {
     	 	 secondrow = ListAdd(secondrow,blech);
     	  }
      }
    }
    /* Schubladenauszug laesst keine GGPL Montage zu */
    secondrow = FilterList(secondrow,'element',`ConnectedDockCount(element, 'blech2schubladenauszug') gt 0;`);
    /* Unterhalb Einschuebtuere koennen keine GGPLs montiert werden */
    secondrow = FilterList(secondrow,'element',`call einschubTuereGGW(element,parts);`);
    ggwbleche[0] = SortByValue(lowestrow,'-Number(SubStr(GetTypeName(element),StrLen(GetTypeName(element))-3));');
    ggwbleche[1] = SortByValue(secondrow,'-Number(SubStr(GetTypeName(element),StrLen(GetTypeName(element))-3));');
    ggwbleche[2] = JoinList(ggwbleche[0],ggwbleche[1]);
	  return ggwbleche;
	}

