def einschubTuereGGW(part,parts) {
    my hasEinschubTuere = false;
    my list = List();
    my gelenke = FilterList(parts,'element',`not IsSubTypeOf(element,'einschubtuergelenk_l');`);        
    for (my gelenk : gelenke) {
      my relpos = RelativePartPos(part,gelenk);
      my x  = Abs(Round(relpos['x']));
      my y  = Abs(Round(relpos['y']));
      my z  = Abs(Round(relpos['z']));
      list = List(x,y,z);
      list = SortByValue(list, 'element;');
      my einschub500 = list[0] eq 1 and list[1] eq 8;
      my einschub750 = list[0] eq 0 and list[1] eq 1;
      if (einschub500 or einschub750) {
         hasEinschubTuere = true;
         break;
      }
    }
    return hasEinschubTuere;
  }

