		my maxGGW = 0; 
		my allbleche = JoinList(bleche[0], bleche[1]);
		my infoGGW = List();
		for (my blech : allbleche) {
		   infoGGW = call maxPlattenGGW(blech);
		   maxGGW = maxGGW + infoGGW[0];
		}

		return maxGGW;
		}

def frontSeiteNormal(part) {
    my direction = List();
    my normal = true;
    my rohrdocks = List();
    my hoeheGGW = PartPos(part)['z'];
    my tiefeGGW = Feature('f_ggwOrientierungTiefe');    
    my rohre = List();
    my rohr = null;
    my blech = null;
    my bleche = List();
    my offeneSeiten = List();
    my blechdocks = ConnectedDocksOfType(part, 'blech2rohr');
    for (my dock : blechdocks) {
      rohre = ListAdd(rohre,DockGetConnectedPart(dock));
    }
    for (my rohr : rohre) {
      rohrdocks = ConnectedDocksOfType(rohr, 'rohr2blech');
      bleche = List();
      for (my rohrdock : rohrdocks) {
        bleche = ListAdd(bleche,DockGetConnectedPart(rohrdock));
      }
      bleche = FilterList(bleche,'element',`element eq part;`);
      bleche = FilterList(bleche,'element',`PartPos(element)['z'] le hoeheGGW;`);
      if (not bleche[0]) {
        offeneSeiten = ListAdd(offeneSeiten, rohr);
      }
    }
    offeneSeiten;
    if (Size(offeneSeiten) gt 0) {
      rohr = offeneSeiten[0];
      /* bei quadratisch gedrehten Bodenblechen, da hier das  tiefen Tiefen Feature nicht genuegt */
      /* wird gebraucht auch bei showPlattenGGW */
      direction[1] = call rotateToFront(part,rohr);
      if (not tiefeGGW) {  
        normal = RelativePartPos(part, offeneSeiten[0])['y'] lt 0 and not direction[1];
      } else {
        normal = RelativePartPos(part, offeneSeiten[0])['x'] lt 0;
      }
    }
    direction[0] = normal;
    return direction;
    }

def yDirectionGGW(part) {
    my ydirection = false;
    my rohrdocks = List();
    my rohre = List();
    my rohr = null;
    my blech = null;
    my length = PartAttr(part, 'length');
    my width = PartAttr(part, 'width');
    my hc_length = 0;
    my bleche = List();
    my ohneMetallseiten = List();
    my offeneSeiten = List();

    offeneSeiten = call findOffeneSeiten(part);
    my count = Size(offeneSeiten);

    if (count gt 0 and count lt 4) {
     rohr = offeneSeiten[0];
     hc_length = PartAttr(offeneSeiten[0],'hc_length');
     /* Wenn Rohrlaenge gleich Blechlaenge */
     if (hc_length eq length) {
      ydirection = false;
     } else {     
      ydirection = true;
     }
    }
    if (width eq 395) {
       /* Ausnahme Korpus 395 */
      my group_parts = GetComponentListOfConnectionId(ConnectionId(part));
      my auszug395 = Bool(Size(FilterList(group_parts,'element',`not IsSubTypeOf(element,'schubladenauszug395');`)));
      if (auszug395) {
         ydirection = true;
      }

    }
    return ydirection;
    }

def findOffeneSeiten(part) {
    my offeneSeiten = List();
    my rohrdocks = List();
    my rohre = List();
    my rohr = null;
    my blech = null;
    my bleche = List();
    my ohneMetallseiten = List();
    my blechhoehe = PartPos(part)['z'];
    my verkleidung_oberhalb = false;
    my glaeser = List();

    my sortex = `PartAttr(element1,'hc_length') lt PartAttr(element2,'hc_length');`;

    /* Berechnung ob Rohre eine Metallverkleidung haben sind */
    my blechdocks = ConnectedDocksOfType(part, 'blech2rohr');
    for (my dock : blechdocks) {
      rohre = ListAdd(rohre,DockGetConnectedPart(dock));
    }
    for (my rohr : rohre) {
      rohrdocks = ConnectedDocksOfType(rohr, 'rohr2blech');
      bleche = List();
      for (my rohrdock : rohrdocks) {
        bleche = ListAdd(bleche,DockGetConnectedPart(rohrdock));
      }
      bleche = FilterList(bleche,'element',`element eq part;`);
      verkleidung_oberhalb = Bool(Size(FilterList(bleche,'element',`PartPos(element)['z'] lt blechhoehe;`)));
      if (verkleidung_oberhalb) {
      bleche = FilterList(bleche,'element',`PartPos(element)['z'] lt blechhoehe;`);
      }
      bleche = FilterList(bleche,'element',`element eq part;`);
      if (not bleche[0]) {
        ohneMetallseiten = ListAdd(ohneMetallseiten, rohr);
      }
    }
    /* Berechnung ob restliche Rohre verglast sind */
    rohre = ohneMetallseiten;
    /* Message(Size(ohneMetallseiten) ++ ', ' ++ verkleidung_oberhalb); */
    for (my rohr : rohre) {
      rohrdocks = ConnectedDocksOfType(rohr, 'rohr2glashalter');
      glaeser = List();
      for (my rohrdock : rohrdocks) {
        glaeser = ListAdd(glaeser,DockGetConnectedPart(rohrdock));
      }

      verkleidung_oberhalb = Bool(Size(FilterList(glaeser,'element',`PartPos(element)['z'] lt blechhoehe;`)));
      if (verkleidung_oberhalb) {
      glaeser = FilterList(glaeser,'element',`PartPos(element)['z'] le blechhoehe;`);
      }
      if (not glaeser[0]) {
        offeneSeiten = ListAdd(offeneSeiten, rohr);
      }
    }
    /* Sortierung der offenen Rohre nach Laenge, die lange Seite zuerst */
    offeneSeiten = Sort(offeneSeiten,sortex);

    return offeneSeiten;
    }

def plattenRichtungNormalGGW(part) {
    my normalrichtung = true;
    my normalrichtungcheck = true;
    my rotz = 0;
    my vol = GetRefVolumes(part, 'mainstructure')[0];
    my teleskopauszugliste = List();
    my teleskopauszug = null;
    my schublade = false;
    if (vol) {
      if (BeginsWith(GetTypeName(part),'kurzblech')) {
        teleskopauszugliste = ChildrenListOfTypeDeep(vol,'teleskopauszug_l');
        teleskopauszug = FilterList(teleskopauszugliste,'element',`Round(Abs(RelativePartPos(part, element)['z'])) gt 4;`)[0];
        if (teleskopauszug) {
          if (Round(RelativePartRot(part, teleskopauszug)['z']) eq -90) {
            normalrichtung = false;
          }
        }
      } else {
        normalrichtungcheck = call frontSeiteNormal(part);
        normalrichtung = normalrichtungcheck[0];
      }
    }
    return normalrichtung;
  }

