def paramCalculationSafetyGUI(_sftparams) {
     my sftGUIparams = List();
     my kippgefahr = _sftparams[2];
     my count_ggw_articles = _sftparams[3];
     my group_parts = _sftparams[6];
     my mode = _sftparams[7];
     my haskippgefahrExtern = _sftparams[12];
     my haskippgefahrMovable = _sftparams[1];
     my missingcount = _sftparams[8];
     my missingweight = kippgefahr[1];
     my missingmoment = kippgefahr[3];
     my blecheGGW = call groupBlechListGGW(group_parts);
     my maxbleche = call assignGGW(blecheGGW,missingweight,missingcount);
     my allbleche = call assignGGW(blecheGGW,9999999,999999);
     my rest_weight = maxbleche[0];
     my countGGW = call countGGW(maxbleche[1]);
     my countAllGGW = call countGGW(allbleche[1]);
     my weightGGW = maxbleche[2];
     /* muessen immer gerechnet werden: my wall_anchoring_count = call calculateWandVerankerung(_sftparams);
     my floor_anchoring_count = call calculateBodenVerankerung(_sftparams); */
     sftGUIparams[0] = ''; /* reserve */
     sftGUIparams[1] = blecheGGW; /* blecheGGW */
     sftGUIparams[2] = countGGW;  /* countGGW */
     sftGUIparams[3] = (Bool(Size(blecheGGW[2])) and count_ggw_articles lt countGGW) or missingweight le 0 or mode eq 'show'; /* using_blecheGGW */
     sftGUIparams[4] = weightGGW; /* Gewicht der moeglichen GGPLs */
     sftGUIparams[5] = rest_weight;
     sftGUIparams[6] = rest_weight lt 3; /* kann alles mit GGPL abgedeckt werden */
     sftGUIparams[7] = call calculateWandVerankerung(_sftparams); /* Anzahl Wandanker */
     sftGUIparams[8] = call calculateBodenVerankerung(_sftparams); /* Boden  Wandanker */
     sftGUIparams[9] = countAllGGW; /* Alle GGPLs, die moeglich sind */
     sftGUIparams[10] = haskippgefahrExtern; /* Fuer Grafikanzeige */
     sftGUIparams[11] = haskippgefahrMovable; /* Fuer Grafikanzeige */
     return sftGUIparams;
     }

def tiltDangerPointerDistance(tilt_moment) {
    my distance = 0;
    my start = 5;
    my max = 505;   
    my middle = 172;
    my minmoment = 10000;
    my maxmoment = -20000;
    my range = minmoment + maxmoment * -1;
    my factor = max / range;
    if ( tilt_moment eq 0 ) {
      distance = start + middle;
    } else if (tilt_moment gt 0) {
      if (tilt_moment gt minmoment) {
        tilt_moment = minmoment;
      }
      distance = middle - (factor * tilt_moment) + start;
    } else if (tilt_moment lt 0) {
       if (tilt_moment le maxmoment) {
        tilt_moment = maxmoment;
      }
      distance = middle + (factor * tilt_moment * -1) + start;  
    }
    return distance;  
    }

def countSchubladen(group_parts) {
    my countSL = List(0,0);
    my countSLvorne = 0; /* Anzahl Schubladen nach vorne */
    my countSLhinten = 0; /* Anzahl Schubladen nach vorne */
    /* Schubladenauszuege sind immer statisch */
    my listSLA = FilterList(group_parts,'element',`not IsSubTypeOf(element, 'schubladenauszug');`);
    my referenceAuszug = listSLA[0];
    my SLA1 = FilterList(listSLA,'element',`PartRot(element)['z'] eq PartRot(referenceAuszug)['z'];`);
    my SLA2 = FilterList(listSLA,'element',`PartRot(element)['z'] ne PartRot(referenceAuszug)['z'];`);

    for (my i : IndexList(Size(SLA1))) {
      my sla1 = SLA1[i];
      /* Schubladen zaehlen */
      countSLvorne = countSLvorne + ConnectedDockCount(sla1,'schubladenauszug_l2schublade_l');
    }
    for (my i : IndexList(Size(SLA2))) {
      my sla2 = SLA2[i];
      /* Schubladen zaehlen */
      countSLhinten = countSLhinten + ConnectedDockCount(sla2,'schubladenauszug_l2schublade_l');
    }

    my countSLmovable = countSLvorne;
    my countSLstatic = countSLhinten;
    if (countSLhinten gt countSLvorne) {
       countSLmovable = countSLhinten;
       countSLstatic = countSLvorne;
    }  
    countSL[0] = countSLmovable; /* movable Schubladen */
    countSL[1] = countSLstatic; /* Schubladen  statisch*/
    return countSL;
  }

def countSpezAZT(korb) {
    my spezcount = 0;
    my column = List();
    my columncount = Size(korb);
    for (my j : IndexList(columncount)) {
      column = korb[j];
      for (my i : IndexList(Size(column))) {
        my parent = Parent('mainstructure',column[i]);
        my aztuere = ParentOfType(parent,'mainstructure','ausziehtuertablarset');
        /* aztuerschubladenset koennen keine Tablare innerhalb haben: stimmt nicht deshalb auskommentiert */
        /* if (aztuere and not ParentOfType(aztuere,'mainstructure','aztuerschubladenset')) { */
        if (aztuere) {         
          my vol = MainRoot(aztuere);
          if (vol) {
            my teles = FilterList(column,'element',`MainRoot(element) ne vol;`);
            if (Size(teles) gt 1) {
              spezcount = spezcount + 1;
            }
          }
        }
      }
    }
    if (spezcount gt columncount) {
      /* AZ-Tablar mit AZ-Tuere kann pro Fach-Kolonne nur 1x auftreten */
      spezcount = columncount;
    }
    return spezcount;
    }

def countSideAZT(aztfrontlist) {
    my posfrontlist = List();
    for (my azt : aztfrontlist) {
	    my pos = PartPos(azt);
	    my hpos = Round(pos['x']) ++ '_' ++ Round(pos['y']);
	    posfrontlist = ListAdd(posfrontlist,hpos);
	 }
   /* How many different columns exists */
	 posfrontlist = UniqueList(posfrontlist);
	 my frontazt = Size(posfrontlist);
	 my spezAZT = 0;
	 my posfrontrowlist = List();
	 for ( my i : IndexList(Size(posfrontlist))) {
     /* assign each azt to a column */
	 	 for (my azt : aztfrontlist) {
	     my pos = PartPos(azt);
	     my hpos = Round(pos['x']) ++ '_' ++ Round(pos['y']);
	     if (posfrontlist[i] eq hpos) {
	       posfrontrowlist[i] = ListAdd(posfrontrowlist[i],azt);
	     }
	   }
	 }
   /* check how many aztablar are in same volume above aztuere */
   spezAZT = call countSpezAZT(posfrontrowlist);
   frontazt = frontazt + spezAZT;	
   return frontazt;
   }

def countAZT(group_parts) {
    my bestcountAZT = List();
    my countAZT = List();
    my spezAZT = 0;
    my move_countAZT = 0;
    my static_countAZT = 0;
    my aztbaselist = FilterList(group_parts,'element',`not IsSubTypeOf(element, 'teleskopauszug_l');`);
    my countAZT = Size(aztbaselist);
    my aztfrontlist =  List();
    my aztbacklist =  List();
    my baserotz = 0;
    /* separate front/back first by rotation */
    for (my i : IndexList(countAZT)) {
      my azt = aztbaselist[i];
      my rotz = Round(PartRot(azt)['z']);
      if ( i eq 0) {
        baserotz = rotz;
       }
      if (rotz eq baserotz) {
        aztfrontlist = ListAdd(aztfrontlist,azt); 
      } else {
        aztbacklist = ListAdd(aztbacklist,azt);
      }
    }
    /* count on each side */
    my frontAZTcount = call countSideAZT(aztfrontlist);
    my backAZTcount = call countSideAZT(aztbacklist);
    if (frontAZTcount ge backAZTcount) {
    	move_countAZT = frontAZTcount;
    } else {
      move_countAZT = backAZTcount;
    }
    static_countAZT = countAZT - move_countAZT;
    bestcountAZT[0] = move_countAZT;
    bestcountAZT[1] = static_countAZT;
    return bestcountAZT;
  }

def assignGGW(allbleche,missingweight,missingcount) {
    my completion = List();
    completion[0] = 0;
    my assignment = List();
    my bleche = List();
    my hallerE = false;
    my kurzblech = false;
    my new_weight = 0;
    my finished = false;
    my ggwblech = List();
    my rowweigth = 0;
    my totalweight = 0;
    my count =  0;

    /* Iteration ueber die 2 untersten Blech-Reihen */
    for (my row : IndexList(2)) {
      bleche = allbleche[row];
      /* Iteration ueber max. Anzahl meoeglicher GGW pro Blech */
      for (my i : List(1,2,3)) {
        /* Iteration ueber Anzahl bleche pro Reihe */
        for (my j : IndexList(Size(bleche))) {
          ggwblech = call maxPlattenGGW(bleche[j]);
          if (i le ggwblech[0] and missingweight gt totalweight) {
            hallerE = Feature(bleche[j],'f_hallerE');
            kurzblech = BeginsWith(GetTypeName(bleche[j]),'kurzblech');
            if (missingcount gt count) {
              new_weight = call maxWeightGGW(ggwblech[2],1,hallerE,kurzblech);
              totalweight = totalweight + new_weight;
              /* Message(GetTypeName(bleche[j]) ++ ', ' ++ ggwblech[2] ++ ', ' ++ new_weight ++ ', ' ++ totalweight); */
              if (totalweight ge missingweight) {
                assignment[row][j] = List(bleche[j],i);
                count = count + 1;
                finished = true;
                break;
              } else {             

                 assignment[row][j] = List(bleche[j],i);
                 count = count + 1;
              } 
            } else {
              finished = true;
              break;
            }    
          }
          if (finished) {
            break;
          }
        }
        if (finished) {
          break;
        }
      } 
    }    
    /* after all bleche are full assigned and weight is still left */
     if (totalweight lt missingweight) {
       completion[0] = missingweight - totalweight;
     }
     completion[1] = assignment;
     completion[2] = totalweight;
     return completion;
   }

