def calculateBodenVerankerung(_sftparams) {
    my count = 0; 
    my anz_raw = 0;
    my force = safetyparams['name','forces']['force']['name','bodenanker']['value'];
    my floorfactor = safetyparams['name','statics']['static']['name','floor_calcfactor']['value'];
    my kippgefahr = _sftparams[2];
    my missingmoment = 0;
    my diffgewicht = 0;
    my depth = _sftparams[14][1]; /* Ganze Tiefe */
    my static = _sftparams[18]; /* calcAZE = statische Berechnung */
      if (force ne 0 and floorfactor ne 0 and depth ne 0) {   
        if (static) {
          diffgewicht = Abs(_sftparams[22][0]);
          anz_raw = diffgewicht/force/floorfactor;
        } else {
          missingmoment = Abs(kippgefahr[3]);
          anz_raw = missingmoment/depth/force; 
        }
        my anz = Round(anz_raw,1.0);
        my anz_floor = Floor(anz_raw);
        anz eq anz_floor ? count = anz +1 : count = anz; 
        count = count * 2; /* hinten + vorne: gemaess excel spez. */

      } else {
        count = 0;
      }
    count;
    my bodenkugeln = _sftparams[4];
    if (count gt bodenkugeln) { 
      count = bodenkugeln;
    } else if (count le 0) {
      count = 1;
    }

    return count;
  }

def calculateWandVerankerung(_sftparams) {
     my count = 0; 
     my force = safetyparams['name','forces']['force']['name','wandanker']['value'];
     my wallfactor = safetyparams['name','statics']['static']['name','wall_calcfactor']['value'];
     my kippgefahr = _sftparams[2];
     my missingmoment = kippgefahr[3];
     my static = _sftparams[18]; /* calcAZE = statische Berechnung */
     my diffgewicht = Abs(_sftparams[22][0]);
     if (diffgewicht ne 0) {
      if (force ne 0 and wallfactor ne 0) {     
        my anz_raw = diffgewicht/force/wallfactor;
        my anz = Round(anz_raw,1.0);
        my anz_floor = Floor(anz_raw);
        anz eq anz_floor ? count = anz +1 : count = anz;
      } else {
        count = 0;
      }
     }
    my bodenkugeln = _sftparams[4];
    my max_wandankerkugeln = bodenkugeln/2;
    if (count gt max_wandankerkugeln) {
       count = max_wandankerkugeln;
    } else if (count le 0) {
       count = 1;
     }
    return count;
   }

