def getRelativeBBoxOfPartListPosition(part, partlist) {
	my result = List();
	my origin = Vector();
	my extent = Vector();
	my e = Max(0,(Size(partlist)-1));
	my step = 0.05;
	partlist = SortByValue(partlist, `Round(PartPos(element)['x'],step);`);
	origin['x'] = Round(PartPos(partlist[0])['x'],step);
	extent['x'] = Round(PartPos(partlist[e])['x'],step) - Round(PartPos(partlist[0])['x'],step);;
	partlist = SortByValue(partlist, `Round(PartPos(element)['y'],step);`);
	origin['y'] = Round(PartPos(partlist[0])['y'],step);
	extent['y'] = Round(PartPos(partlist[e])['y'],step) - Round(PartPos(partlist[0])['y'],step);
	partlist = SortByValue(partlist, `Round(PartPos(element)['z'],step);`);
	origin['z'] = Round(PartPos(partlist[0])['z'],step);
	extent['z'] = Round(PartPos(partlist[e])['z'],step) - Round(PartPos(partlist[0])['z'],step);

	result['origin'] = LocalPos(part, origin);
	result['extent'] = extent;

	result;
};

def getRelativeBBoxOfPartListPosition(part, partlist, docktype) {
	my result = List();

	my docklist = List();
	my docklist_pos = List();
	for (my p: partlist) {
		ListExtend(docklist, ConnectedDocksOfType(p, docktype)); 
	};
	for (my dock: docklist) {
		ListAdd(docklist_pos, LocalDockPos(dock, PartPos(part)));
	}

	my origin = Vector();
	my extent = Vector();

	my e = Max(0,(Size(docklist_pos)-1));
	my step = 2;
	docklist_pos = SortByValue(docklist_pos, `Round(element['x'],step);`);
	origin['x'] = Round(docklist_pos[0]['x'],step);
	extent['x'] = Round(docklist_pos[e]['x'],step) - Round(docklist_pos[0]['x'],step);
	docklist_pos = SortByValue(docklist_pos, `Round(element['y'],step);`);
	origin['y'] = Round(docklist_pos[0]['y'],step);
	extent['y'] = Round(docklist_pos[e]['y'],step) - Round(docklist_pos[0]['y'],step);
	docklist_pos = SortByValue(docklist_pos, `Round(element['z'],step);`);
	origin['z'] = Round(docklist_pos[0]['z'],step);
	extent['z'] = Round(docklist_pos[e]['z'],step) - Round(docklist_pos[0]['z'],step);;


	result['origin'] = LocalPos(part, origin);
	result['extent'] = extent;

	result;
};

def hasURohr(part) {
  	call hasURohr(part, 'value');
  }
  def hasURohr(part, type) {
		def customLocalGetIntersectionInfo(center,direction,part) {
			my info = GetIntersectionInfo(1000,Line(center, direction),'kugel_std',part);
			if (info['part'] EQ null) {
				info = GetIntersectionInfo(1000, Line(center, direction),'',part);
				if (!IsSubTypeOf(info['part'],'kugel_gew') and !IsSubTypeOf(info['part'],'bodenelement') ) {
					info['part'] = null;
				}
			}
			return info;
  		}
  		my pointlist = List();
  		pointlist[0] = List();
  		pointlist[1] = List();
  		pointlist[2] = List();
  		pointlist[3] = List();
  		my ok = true;

		my missing_count = 0;
  		my volume = GetRefVolumes(part, 'mainstructure')[0];
  		my width = PartAttr(part,'width')* 0.1;
  		my length = PartAttr(part,'length')* 0.1;

  		if (true or not volume) {
	  		my w = width;
  			my l = length;
  			my r = 75;

  			my points = List();	 
	  		my bbparts = List();
	  		my bottomparts = List();
  			my p1 = Vector(l/2,0,1);
  			my p2 = Vector(l/2,-r,1);
  			my center= GlobalPos(part,p1); 
			my direction= VectorSub(GlobalPos(part,p2), center);
			/* center and direction are now in the global coordinate system */
			my info = call customLocalGetIntersectionInfo(center,direction,part);
			if (not info['part']) {
				my p1 = Vector(0,-w/2,1);
  				my p2 = Vector(r,-w/2,1);
  				my center= GlobalPos(part,p1); 
  				my direction= VectorSub(GlobalPos(part,p2), center);
				info= call customLocalGetIntersectionInfo(center,direction,part);
			}
  			my rightbottom = info['part']; 
  			ListAdd(bbparts, rightbottom);

  			my p1 = Vector(l/2,0,1);
  			my p2 = Vector(l/2,r,1);
  			my center= GlobalPos(part,p1);
			my direction= VectorSub(GlobalPos(part,p2), center);
			my info= call customLocalGetIntersectionInfo(center,direction,part);
			if (not info['part']) {
				my p1 = Vector(0,w/2,1);
  				my p2 = Vector(r,w/2,1);
  				my center= GlobalPos(part,p1); 
  				my direction= VectorSub(GlobalPos(part,p2), center);
				info= call customLocalGetIntersectionInfo(center,direction,part);
			}
  			my righttop = info['part'];
  			ListAdd(bbparts, righttop); 

  			my p1 = Vector(-l/2,0,1);
  			my p2 = Vector(-l/2,r,1);
  			my center= GlobalPos(part,p1);
			my direction= VectorSub(GlobalPos(part,p2), center);
			my info= call customLocalGetIntersectionInfo(center,direction,part);
			if (not info['part']) {
				my p1 = Vector(0,w/2,1);
  				my p2 = Vector(-r,w/2,1);
  				my center= GlobalPos(part,p1); 
  				my direction= VectorSub(GlobalPos(part,p2), center);
				info= call customLocalGetIntersectionInfo(center,direction,part);
			}
  			my lefttop = info['part'];
  			ListAdd(bbparts, lefttop);

  			my p1 = Vector(-l/2,0,1);
  			my p2 = Vector(-l/2,-r,1);
  			my center= GlobalPos(part,p1);
			my direction= VectorSub(GlobalPos(part,p2), center);
			my info= call customLocalGetIntersectionInfo(center,direction,part);
			if (not info['part']) {
				my p1 = Vector(0,-w/2,1);
  				my p2 = Vector(-r,-w/2,1);
  				my center= GlobalPos(part,p1); 
  				my direction= VectorSub(GlobalPos(part,p2), center);
				info= call customLocalGetIntersectionInfo(center,direction,part); 
			}
  			my leftbottom = info['part'];
  			ListAdd(bbparts, leftbottom);

  			my bbox = GlobalBoundingBox(bbparts, 1000);

  			width = Round(VectorLength(VectorSub(PartPos(righttop), PartPos(rightbottom)))); 
	  		length = Round(VectorLength(VectorSub(PartPos(rightbottom), PartPos(leftbottom)))); 

  			for (my k: bbparts) {
  				my direction = Vector(0,0, 15);
  				my center = PartPos(k);
  				my p1 = Vector(0.4,0.4,0);
  				my center = GlobalPos(k, p1);
  				center['z'] = 0;
  				my info= call customLocalGetIntersectionInfo(center,direction,part);
  				if (info['part'] ne null and PartPos(info['part'])['z'] le 14) {
  					ListAdd(bottomparts, info['part']);
  				}
  			}

  			if (Size(bbparts) ne Size(bottomparts)) {
  				if (type eq 'value') {
  					return false;

  				}

  			} else {
  				for (my k: bottomparts) {
  					my rohrdocks = ConnectedDocksOfType(k, 'kugel2rohr');
  					if (Size(rohrdocks) eq 1) {
  						if (type eq 'value') { 
  							return false;
  						}

  					}
  				}
  			}

  		};
	  	{


	  		my refkugel = SortByValue(FilterList(GetComponentListOfType('kugel'), 'p', `not (ConnectionId(p) eq ConnectionId(part));`), `PartPos(element)['z'];`)[0];
	  		my z = PartPos(refkugel)['z'] -3;
	  		my zdir = 5;
	  		my step = 2.4;
	  		my indexlist = IndexList(Floor(width/step));
	  		my start = PartPos(rightbottom);
	  		my start_offset = 1;
	  		my direction = Vector(0,0,zdir);

	  		/* rechts */
	  		for (my index: indexlist) {

				my dir = VectorSub(PartPos(righttop), PartPos(rightbottom)); 
				dir = VectorNormalize(dir); 
				my center = VectorAdd(start, VectorMult(dir, ((start_offset+index)*step)));
				center['z'] = z; ;
				ListAdd(pointlist[0], center);

				my info= GetIntersectionInfo(1000, Line(center, direction),'rohr', part);
				if (info['part'] eq null and index lt (Size(indexlist)-1)) {
					info= GetIntersectionInfo(1000, Line(center, direction),'kugel', part);
				}

				ok = info['part'] ne null;

				if (not ok and type eq 'value') {
					missing_count = missing_count + 1;

					break;
				};

	  		};

	  		/* links */
	  		my start = PartPos(leftbottom);
	  		my indexlist = IndexList(Floor(width/step)-start_offset);

	  		for (my index: indexlist) {
	  			my dir = VectorSub(PartPos(lefttop), PartPos(leftbottom)); 
				dir = VectorNormalize(dir); 
				my center = VectorAdd(start, VectorMult(dir, ((start_offset+index)*step)));
				center['z'] = z; ;
				ListAdd(pointlist[1], center);

				my info= GetIntersectionInfo(1000, Line(center, direction),'rohr', part);
				if (info['part'] eq null and index lt (Size(indexlist)-1)) {
					info= GetIntersectionInfo(1000, Line(center, direction),'kugel', part);
				}

				ok = info['part'] ne null;

				if (not ok and type eq 'value') {
					missing_count = missing_count + 1;

					break;
				};
	  		}

	  		/* oben */
	  		my start =  PartPos(lefttop);
	  		my indexlist = IndexList(Floor(length/(step+0.1)));

	  		for (my index: indexlist) {
	  			my dir = VectorSub(PartPos(righttop), PartPos(lefttop)); 
				dir = VectorNormalize(dir); 
				my center = VectorAdd(start, VectorMult(dir, ((start_offset+index)*step)));
				center['z'] = z; ;
				ListAdd(pointlist[2], center);

				my info= GetIntersectionInfo(1000, Line(center, direction),'rohr', part);
				if (info['part'] eq null and index lt (Size(indexlist)-1)) {
					info= GetIntersectionInfo(1000, Line(center, direction),'kugel', part);
				}

				ok = info['part'] ne null;

				if (not ok and type eq 'value') {
					missing_count = missing_count + 1;
					break;
				};
	  		}

	  		/* unten */
	  		my start =  PartPos(leftbottom);
	  		my indexlist = IndexList(Floor(length/(step+0.1)));

	  		for (my index: indexlist) {
	  			my dir = VectorSub(PartPos(rightbottom), PartPos(leftbottom)); 
				dir = VectorNormalize(dir); 
				my center = VectorAdd(start, VectorMult(dir, ((start_offset+index)*step)));
				center['z'] = z; ;
				ListAdd(pointlist[3], center);

				my info= GetIntersectionInfo(1000, Line(center, direction),'rohr', part);
				if (info['part'] eq null and index lt (Size(indexlist)-1)) {
					info= GetIntersectionInfo(1000, Line(center, direction),'kugel', part);
				}

				ok = info['part'] ne null;

				if (not ok and type eq 'value') {
					missing_count = missing_count + 1;
					break;
				};
	  		}
  		};


  		if (missing_count gt 1 and type eq 'value') {
  			ok = false;
  		} else {
  			ok = true;
  		};

  		if (type eq 'points') {
  			return pointlist;
  		};
  		ok;	

  };

def kugelStrukturEinsatzStabilitaet(part) {
		my stabil = true;
		my count = 0;
		my rohr = null;
		my groupid = '';
		groupid = Feature(part,'_PXi_permanent_group_id');
		/* Message(groupid); */
		if (IsSubTypeOf(part,'einsatzverkleidung') and groupid eq '') {
			rohr = DockGetConnectedPart(Dock(part,'blech2rohr','1'));
			/* Message(rohr); */
			groupid = rohr ? Feature(rohr,'_PXi_permanent_group_id') : groupid;
		}
		/* Message(groupid); */
		my group_parts = call groupIdPartList(groupid);
		my total_kugeln = FilterList(group_parts,'element',`not IsSubTypeOf(element,'kugel_std');`);
		my boden_kugeln = FilterList(total_kugeln,'element',`PartPos(element)['z'] gt 14;`);
		my depth = PartAttr(part, 'width')/10;
		my length = PartAttr(part, 'length')/10;
		boden_kugeln = FilterList(boden_kugeln,'element',`not (Abs(Round(RelativePartPos(part, element)['x'], 0.01)) le length/2 and Abs(Round(RelativePartPos(part, element)['y'],0.01)) le depth/2);`);
		/* Message(boden_kugeln); */
		my rohre = List();
		my hilfsrohre = 0;
		my kugeln = List();
		my match = 0;
		/* Rohre holen */
		my blechdocks = ConnectedDocksOfType(part, 'blech2rohr');
		for (my dock : blechdocks) {
			rohre = ListAdd(rohre,DockGetConnectedPart(dock));
		}
		/* Check ob Hilfsrohre vorhanden sind */
		/* Hilfrohre haben eine pseudo Kugel eingebaut */
		hilfsrohre = Size(FilterList(rohre,'element',` not IsSubTypeOf(element,'gewindehilfsrohr');`));
		/* Alle verbundenen Kugeln holen */
		for (my rohr : rohre) {
			if (DockGetConnectedPart(Dock(rohr,'rohr2kugel','1')) NE null) {
				kugeln = ListAdd(kugeln,DockGetConnectedPart(Dock(rohr,'rohr2kugel','1')));
			}
			if (DockGetConnectedPart(Dock(rohr,'rohr2kugel','2')) NE null) {
				kugeln = ListAdd(kugeln,DockGetConnectedPart(Dock(rohr,'rohr2kugel','2')));
			}
		}
		/* mehrfach gefundene Kugeln eliminieren */
		kugeln = UniqueList(kugeln);
		count = Size(kugeln);
		/* Wenn Hilfsrohr, dann kann eine Kugel weniger auf dem Boden sein */
		 count = count - hilfsrohre;
		my bodenrohre = List();
		/* hat jede Kugel ihr Gegenstueck auf dem Boden */
		for (my kugel : kugeln) {
			my kugelpos = PartPos(kugel);
			for (my bkugel : boden_kugeln) {
				my bkugelpos = PartPos(bkugel);
				my xpos = Round(kugelpos['x'],0.1) eq Round(bkugelpos['x'],0.1);
				my ypos = Round(kugelpos['y'],0.1) eq Round(bkugelpos['y'],0.1);
				if ( xpos and ypos ) {
					match = match + 1;
					my rohre = FilterList(call connectedPartsByDockType(bkugel, 'kugel2rohr'), 'p', `not ((Round(PartPos(p)['z']) eq Round(PartPos(bkugel)['z'])));`);
					rohre = FilterList(rohre,'element',`not (Abs(Round(RelativePartPos(part, element)['x'])) le length/2 and Abs(Round(RelativePartPos(part, element)['y'])) le depth/2);`);
					for (my r: rohre) {
						my rohr_kugel = FindPart(r, 'rohr2kugel',1);
						if (rohr_kugel and not InList(bodenrohre, rohr_kugel)) {
							ListAdd(bodenrohre, rohr_kugel);
						}
						my rohr_kugel = FindPart(r, 'rohr2kugel',2);
						if (rohr_kugel and not InList(bodenrohre, rohr_kugel)) {
							ListAdd(bodenrohre, rohr_kugel);
						}
					}
				}
			}	
		}
		/* wenn match gleich wie obere Kugeln ist es stabil */
		stabil = match ge count;
		my result = List();
		result['stabil'] = stabil;
		result['bodenkugeln'] = boden_kugeln;
		result['rohrkugeln'] = bodenrohre;
		return result;  
	}

def safetyParamStore(store,search) {
		my param = '';
		/* my store = call safetyDummy(call groupIdPartList(groupid)); */
    my feature = 'f_' ++ search;
    if(Bool(store)) {
	    if (HasFeature(store,feature)) {
	        param = Feature(store,feature);
	    }
	  }
		return param;
  }

def safetyAssigned(part) {
		my assigned = false;
		my groupid = Feature(part,'_PXi_permanent_group_id');
		my group_parts = call groupIdPartList(groupid);
		my store = call safetyDummy(group_parts);
		if(store) {
		assigned = Feature(store,'f_safetyAssigned');
		}
		return  assigned;
		}

def getSafetySet(part) {
	my artnr = '';
	my orientierungtiefe = String(Feature(part, 'f_ggwOrientierungTiefe'));
	/* haller e nur relevant für normalblech in breite 395 */
	my haller_e = Bool(Feature(part, 'f_hallerE')) and BeginsWith(GetTypeName(part), 'blech') and GetTypeName(part) ~ '_395' ? '1' : '0';
	my table = TableRows(SAFETY,List('orientierungtiefe','haller_e'),List(orientierungtiefe,haller_e), false);
	/* add the non haller_e rows  for fallback */
	ListExtend(table, TableRows(SAFETY,List('orientierungtiefe','haller_e'),List(orientierungtiefe,'0'), false));
	for (my e: table) {
		my type = GetTypeName(part);
		my types = StringToList(e['type'], ',');	
		if (InList(types,type)) {
			artnr = e['Anr'];
			break;
		};
	};
	return artnr;
};
